<!-- 功能说明
管理员密码修改专用页面，支持旧密码校验、新密码两次输入一致性校验、密码强度提示，
提交修改后同步后端更新密码，核心对接密码修改接口，确保密码修改流程安全合规。 -->


<template>
  <view class="password-modify-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <button class="back-btn" @click="navigateBack">
        <image src="/static/images/back.png" class="back-icon"></image>
      </button>
      <text class="header-title">修改密码</text>
    </view>

    <!-- 密码修改表单 -->
    <form class="modify-form" @submit.prevent="submitModify">
      <!-- 旧密码 -->
      <view class="form-item">
        <text class="form-label required">旧密码</text>
        <input 
          class="form-input" 
          v-model="passwordForm.oldPassword" 
          placeholder="请输入当前登录密码"
          :type="showOldPwd ? 'text' : 'password'"
          maxlength="20"
        ></input>
        <image 
          :src="showOldPwd ? '/static/images/icon-hide.png' : '/static/images/icon-show.png'" 
          class="eye-icon"
          @click="toggleOldPwd"
        ></image>
      </view>

      <!-- 新密码 -->
      <view class="form-item">
        <text class="form-label required">新密码</text>
        <input 
          class="form-input" 
          v-model="passwordForm.newPassword" 
          placeholder="请输入6-20位新密码"
          :type="showNewPwd ? 'text' : 'password'"
          maxlength="20"
          @input="checkPasswordStrength"
        ></input>
        <image 
          :src="showNewPwd ? '/static/images/icon-hide.png' : '/static/images/icon-show.png'" 
          class="eye-icon"
          @click="toggleNewPwd"
        ></image>
        <!-- 密码强度提示 -->
        <view class="password-strength" v-if="passwordForm.newPassword.length > 0">
          <text class="strength-label">密码强度：</text>
          <view class="strength-bars">
            <view class="strength-bar" :class="getStrengthClass(1)"></view>
            <view class="strength-bar" :class="getStrengthClass(2)"></view>
            <view class="strength-bar" :class="getStrengthClass(3)"></view>
          </view>
          <text class="strength-text">{{getStrengthText()}}</text>
        </view>
      </view>

      <!-- 确认新密码 -->
      <view class="form-item">
        <text class="form-label required">确认新密码</text>
        <input 
          class="form-input" 
          v-model="passwordForm.confirmPassword" 
          placeholder="请再次输入新密码"
          :type="showConfirmPwd ? 'text' : 'password'"
          maxlength="20"
          @input="checkPasswordMatch"
        ></input>
        <image 
          :src="showConfirmPwd ? '/static/images/icon-hide.png' : '/static/images/icon-show.png'" 
          class="eye-icon"
          @click="toggleConfirmPwd"
        ></image>
        <text class="password-match" :class="passwordMatch ? 'match-success' : 'match-error'" v-if="passwordForm.confirmPassword.length > 0">
          {{passwordMatch ? '密码一致' : '两次输入密码不一致'}}
        </text>
      </view>

      <!-- 提交按钮 -->
      <button class="submit-btn" type="submit" :disabled="isSubmitting || !isFormValid()">
        <text v-if="isSubmitting">修改中...</text>
        <text v-else>确认修改</text>
      </button>
    </form>
  </view>
</template>
<script setup>
import { ref, computed } from 'vue';
import { onLoad } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const passwordForm = ref({
  oldPassword: '',
  newPassword: '',
  confirmPassword: ''
});
const showOldPwd = ref(false);
const showNewPwd = ref(false);
const showConfirmPwd = ref(false);
const passwordStrength = ref(0); // 0-无 1-弱 2-中 3-强
const passwordMatch = ref(true);
const isSubmitting = ref(false);

// 切换密码显示/隐藏
const toggleOldPwd = () => {
  showOldPwd.value = !showOldPwd.value;
};

const toggleNewPwd = () => {
  showNewPwd.value = !showNewPwd.value;
};

const toggleConfirmPwd = () => {
  showConfirmPwd.value = !showConfirmPwd.value;
};

// 检查密码强度
const checkPasswordStrength = (e) => {
  const password = e.detail.value;
  let strength = 0;
  // 长度≥6
  if (password.length >= 6) strength += 1;
  // 包含字母和数字
  if (/[a-zA-Z]/.test(password) && /[0-9]/.test(password)) strength += 1;
  // 包含特殊字符
  if (/[^a-zA-Z0-9]/.test(password)) strength += 1;
  passwordStrength.value = strength;
};

// 检查密码一致性
const checkPasswordMatch = (e) => {
  const confirmPwd = e.detail.value;
  passwordMatch.value = confirmPwd === passwordForm.value.newPassword;
};

// 获取密码强度样式类
const getStrengthClass = (level) => {
  if (level > passwordStrength.value) return 'strength-empty';
  switch (passwordStrength.value) {
    case 1: return 'strength-weak';
    case 2: return 'strength-medium';
    case 3: return 'strength-strong';
    default: return 'strength-empty';
  }
};

// 获取密码强度文本
const getStrengthText = () => {
  switch (passwordStrength.value) {
    case 1: return '弱';
    case 2: return '中';
    case 3: return '强';
    default: return '请输入6位以上密码';
  }
};

// 表单校验是否通过
const isFormValid = computed(() => {
  return (
    passwordForm.value.oldPassword.trim() !== '' &&
    passwordForm.value.newPassword.trim() !== '' &&
    passwordForm.value.confirmPassword.trim() !== '' &&
    passwordForm.value.newPassword.length >= 6 &&
    passwordMatch.value &&
    passwordForm.value.newPassword !== passwordForm.value.oldPassword
  );
});

// 提交密码修改
const submitModify = async () => {
  if (!isFormValid.value) return;

  isSubmitting.value = true;
  try {
    const res = await request({
      url: '/api/admin/password/modify',
      method: 'PUT',
      data: {
        oldPassword: passwordForm.value.oldPassword.trim(),
        newPassword: passwordForm.value.newPassword.trim(),
        confirmPassword: passwordForm.value.confirmPassword.trim()
      }
    });

    if (res.success) {
      uni.showToast({ title: '密码修改成功' });
      // 密码修改成功后退出登录，重新登录
      userStore.logout();
      uni.navigateTo({ url: '/pages/admin/login' });
    } else {
      uni.showToast({ title: res.message || '密码修改失败', icon: 'none' });
    }
  } catch (error) {
    uni.showToast({ title: '网络异常，修改失败', icon: 'none' });
  } finally {
    isSubmitting.value = false;
  }
};

// 返回上一页
const navigateBack = () => {
  uni.navigateBack();
};

// 页面加载校验登录状态和权限
onLoad(() => {
  if (!userStore.token || !['ADMIN', 'CUSTOMER_SERVICE'].includes(userStore.userInfo.role)) {
    uni.navigateTo({ url: '/pages/admin/login' });
  }
});
</script>

